export interface PrayerTimes {
  Fajr: string;
  Sunrise: string;
  Dhuhr: string;
  Asr: string;
  Maghrib: string;
  Isha: string;
  [key: string]: string;
}

export interface HijriDate {
  date: string;
  format: string;
  day: string;
  weekday: { en: string; ar: string };
  month: { number: number; en: string; ar: string };
  year: string;
  designation: { abbreviated: string; expanded: string };
}

export interface PlaceResult {
  title: string;
  uri: string;
  snippet?: string;
  rating?: number;
  userRatingCount?: number;
  type?: 'mosque' | 'halal';
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface DailyVerse {
  arabic: string;
  translation: string;
  reference: string;
  reflection: string;
}

export interface DailyHadith {
  arabic: string;
  translation: string;
  source: string;
  narrator: string;
  reflection: string;
}

export interface HifzProgress {
  surahNumber: number;
  memorizedVerses: number[];
  totalVerses: number;
  lastTested?: number;
}

export interface HalalCheckResult {
  isHalal: boolean;
  status: 'halal' | 'haram' | 'mushbooh';
  reason: string;
  concerns: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { DailyVerse, PlaceResult, DailyHadith, HalalCheckResult } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateDailyVerse = async (language: string = 'en'): Promise<DailyVerse | null> => {
  if (!apiKey) return null;
  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a beautiful Quranic verse for today. Include Arabic text, ${langPrompt} translation, reference, and reflection.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            arabic: { type: Type.STRING },
            translation: { type: Type.STRING },
            reference: { type: Type.STRING },
            reflection: { type: Type.STRING },
          },
          required: ["arabic", "translation", "reference", "reflection"],
        },
      },
    });
    return JSON.parse(response.text) as DailyVerse;
  } catch (error) { return null; }
};

export const checkHalalIngredients = async (imageData: string, language: string = 'en'): Promise<HalalCheckResult | null> => {
  if (!apiKey) return null;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: imageData, mimeType: "image/jpeg" } },
          { text: "Analyze the ingredients on this food label. Identify if it is Halal, Haram, or Mushbooh (doubtful). Look for non-halal E-numbers, gelatin source, or alcohol. Reply in JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isHalal: { type: Type.BOOLEAN },
            status: { type: Type.STRING, enum: ["halal", "haram", "mushbooh"] },
            reason: { type: Type.STRING },
            concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["isHalal", "status", "reason", "concerns"]
        }
      }
    });
    return JSON.parse(response.text) as HalalCheckResult;
  } catch (e) { return null; }
};

export const findPlaces = async (lat: number, lng: number, type: 'mosque' | 'halal', language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "", places: [] };
  const query = type === 'mosque' ? "mosques" : "halal restaurants";
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Find the best rated ${query} nearby.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapPlaces = chunks.filter((c: any) => c.maps).map((c: any) => ({
      title: c.maps.title,
      uri: c.maps.uri,
      snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet,
      type: type
    }));
    return { text: response.text, places: mapPlaces };
  } catch (error) { return { text: "", places: [] }; }
};

export const chatWithAi = async (message: string, history: any[], language: string = 'en'): Promise<string> => {
  if (!apiKey) return "API Key missing.";
  const langInstruction = language === 'fr' ? 'Reply in French.' : 'Reply in English.';
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      history,
      config: {
        systemInstruction: `You are Noor, a knowledgeable Islamic AI. Help with Duas, history, and spiritual advice. Be concise and warm. ${langInstruction}`
      }
    });
    const result = await chat.sendMessage({ message });
    return result.text;
  } catch (error) { return "Error connecting to AI."; }
};

import React, { useState, useRef } from 'react';
import { Camera, RefreshCw, AlertTriangle, CheckCircle, Info, X } from 'lucide-react';
import { checkHalalIngredients } from '../services/geminiService';
import { HalalCheckResult } from '../types';

const HalalScanner: React.FC<{ language?: string; onClose: () => void }> = ({ language = 'en', onClose }) => {
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<HalalCheckResult | null>(null);
  const [loading, setLoading] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      alert("Camera access denied.");
    }
  };

  const captureAndScan = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setLoading(true);
    const context = canvasRef.current.getContext('2d');
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context?.drawImage(videoRef.current, 0, 0);

    const imageData = canvasRef.current.toDataURL('image/jpeg').split(',')[1];
    const check = await checkHalalIngredients(imageData, language);
    setResult(check);
    setLoading(false);

    // Stop camera
    stream?.getTracks().forEach(track => track.stop());
    setStream(null);
  };

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center p-6">
      <button onClick={onClose} className="absolute top-6 right-6 text-white p-2 bg-white/10 rounded-full">
        <X size={24} />
      </button>

      {!result && !loading && !stream && (
        <div className="text-center text-white space-y-6">
          <div className="w-24 h-24 bg-emerald-500/20 rounded-full flex items-center justify-center mx-auto ring-4 ring-emerald-500/40">
            <Camera size={48} className="text-emerald-400" />
          </div>
          <h2 className="text-2xl font-bold">Halal Product Scanner</h2>
          <p className="text-slate-400 max-w-xs mx-auto">Scan the ingredient list on any product to check its Halal status with AI.</p>
          <button onClick={startCamera} className="bg-emerald-600 px-8 py-3 rounded-full font-bold shadow-lg shadow-emerald-600/20 active:scale-95 transition-all">
            Start Scanning
          </button>
        </div>
      )}

      {stream && (
        <div className="relative w-full max-w-md aspect-[3/4] rounded-3xl overflow-hidden border-2 border-emerald-500/50">
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
          <div className="absolute inset-x-0 bottom-8 flex justify-center">
            <button onClick={captureAndScan} className="w-16 h-16 bg-white rounded-full border-4 border-emerald-500 flex items-center justify-center active:scale-90 transition-all">
              <div className="w-12 h-12 bg-emerald-600 rounded-full" />
            </button>
          </div>
        </div>
      )}

      {loading && (
        <div className="text-center text-white space-y-4">
          <RefreshCw className="w-12 h-12 text-emerald-500 animate-spin mx-auto" />
          <p className="text-lg font-medium">Analyzing Ingredients...</p>
        </div>
      )}

      {result && (
        <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl p-6 animate-fade-in-up">
          <div className="flex items-center gap-4 mb-6">
            {result.status === 'halal' ? (
              <CheckCircle size={48} className="text-emerald-500" />
            ) : result.status === 'haram' ? (
              <X size={48} className="text-red-500" />
            ) : (
              <AlertTriangle size={48} className="text-amber-500" />
            )}
            <div>
              <h3 className={`text-2xl font-bold uppercase ${result.status === 'halal' ? 'text-emerald-600' : result.status === 'haram' ? 'text-red-600' : 'text-amber-600'}`}>
                {result.status}
              </h3>
              <p className="text-slate-500 text-sm">AI-Powered Analysis</p>
            </div>
          </div>

          <p className="text-slate-700 dark:text-slate-300 mb-4 font-medium">{result.reason}</p>

          {result.concerns.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Identified Concerns</p>
              <div className="flex flex-wrap gap-2">
                {result.concerns.map((c, i) => (
                  <span key={i} className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-lg text-xs font-medium text-slate-600 dark:text-slate-300">
                    {c}
                  </span>
                ))}
              </div>
            </div>
          )}

          <button onClick={() => setResult(null)} className="w-full mt-8 bg-slate-100 dark:bg-slate-800 py-3 rounded-2xl font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-200 transition-colors">
            Scan Another
          </button>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default HalalScanner;

import React, { useState, useEffect } from 'react';
import { BookOpen, CheckCircle, Award, Play, Mic, ChevronRight, Search } from 'lucide-react';
import { HifzProgress } from '../types';

const SURAHS = [
  { id: 78, name: "An-Naba", verses: 40 },
  { id: 67, name: "Al-Mulk", verses: 30 },
  { id: 55, name: "Ar-Rahman", verses: 78 },
  { id: 36, name: "Ya-Sin", verses: 83 },
  { id: 18, name: "Al-Kahf", verses: 110 },
];

const HifzTracker: React.FC<{ language?: string }> = ({ language = 'en' }) => {
  const [progress, setProgress] = useState<HifzProgress[]>([]);
  const [activeSurah, setActiveSurah] = useState<typeof SURAHS[0] | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('hifz_progress');
    if (saved) setProgress(JSON.parse(saved));
  }, []);

  const toggleVerse = (surahId: number, verseNum: number) => {
    setProgress(prev => {
      const existing = prev.find(p => p.surahNumber === surahId);
      let next;
      if (existing) {
        const isSet = existing.memorizedVerses.includes(verseNum);
        next = prev.map(p => p.surahNumber === surahId ? {
          ...p,
          memorizedVerses: isSet ? p.memorizedVerses.filter(v => v !== verseNum) : [...p.memorizedVerses, verseNum]
        } : p);
      } else {
        next = [...prev, { surahNumber: surahId, memorizedVerses: [verseNum], totalVerses: SURAHS.find(s => s.id === surahId)?.verses || 0 }];
      }
      localStorage.setItem('hifz_progress', JSON.stringify(next));
      return next;
    });
  };

  const getPercent = (id: number) => {
    const p = progress.find(p => p.surahNumber === id);
    if (!p) return 0;
    return Math.round((p.memorizedVerses.length / p.totalVerses) * 100);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-xl shadow-blue-900/10 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-2xl" />
        <div className="relative z-10 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold">Hifz Journey</h2>
            <p className="text-blue-100 text-sm opacity-80">Track your memorization progress</p>
          </div>
          <Award size={48} className="text-white/20" />
        </div>
      </div>

      <div className="grid gap-4">
        {SURAHS.map(surah => {
          const percent = getPercent(surah.id);
          return (
            <button
              key={surah.id}
              onClick={() => setActiveSurah(surah)}
              className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between group transition-all"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-50 dark:bg-slate-800 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 transition-colors">
                  {percent === 100 ? <CheckCircle className="text-emerald-500" /> : <BookOpen />}
                </div>
                <div className="text-left">
                  <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.name}</h3>
                  <p className="text-xs text-slate-500">{surah.verses} Verses</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-lg font-bold text-slate-700 dark:text-slate-200">{percent}%</p>
                <div className="w-24 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden mt-1">
                  <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${percent}%` }} />
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {activeSurah && (
        <div className="fixed inset-0 z-50 bg-white dark:bg-slate-950 p-6 flex flex-col animate-fade-in">
          <div className="flex items-center justify-between mb-8">
            <button onClick={() => setActiveSurah(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
              <ChevronRight className="rotate-180" />
            </button>
            <h3 className="text-xl font-bold">{activeSurah.name}</h3>
            <button className="p-2 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 rounded-full">
              <Mic size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-3 pb-8">
            {Array.from({ length: activeSurah.verses }).map((_, i) => {
              const vNum = i + 1;
              const isMem = progress.find(p => p.surahNumber === activeSurah.id)?.memorizedVerses.includes(vNum);
              return (
                <button
                  key={vNum}
                  onClick={() => toggleVerse(activeSurah.id, vNum)}
                  className={`aspect-square rounded-xl flex items-center justify-center text-sm font-bold transition-all ${
                    isMem ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' : 'bg-slate-100 dark:bg-slate-900 text-slate-500 border border-slate-200 dark:border-slate-800'
                  }`}
                >
                  {vNum}
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default HifzTracker;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import PrayerCard from './components/PrayerCard';
import ChatInterface from './components/ChatInterface';
import MosqueFinder from './components/MosqueFinder';
import DailyVerseCard from './components/DailyVerseCard';
import DailyHadithCard from './components/DailyHadithCard';
import QiblaFinder from './components/QiblaFinder';
import TasbihCounter from './components/TasbihCounter';
import QuranReader from './components/QuranReader';
import SettingsModal from './components/SettingsModal';
import HifzTracker from './components/HifzTracker';
import HalalScanner from './components/HalalScanner';
import { getPrayerTimes } from './services/prayerService';
import { PrayerTimes, HijriDate } from './types';
import { Settings, MapPin, Compass, Hand, BookOpen, ChevronRight, Scan, Award, MessageCircle } from 'lucide-react';

const TRANSLATIONS = {
  en: {
    tasbihTitle: "Tasbih",
    tasbihDesc: "Digital Dhikr Counter",
    qiblaTitle: "Qibla",
    qiblaDesc: "Find direction to Kaaba",
    mosquesTitle: "Mosques",
    chatTitle: "Ask Noor AI",
    myLocation: "My Location",
    london: "London",
    dateError: "Islamic Companion",
    hifzTitle: "Memorize",
    hifzDesc: "Track your Hifz journey",
    halalTitle: "Halal Scanner",
    halalDesc: "Check product ingredients"
  },
  fr: {
    tasbihTitle: "Tasbih",
    tasbihDesc: "Compteur de Dhikr",
    qiblaTitle: "Qibla",
    qiblaDesc: "Direction de la Kaaba",
    mosquesTitle: "Mosquées",
    chatTitle: "Demander à l'IA",
    myLocation: "Ma position",
    london: "Londres",
    dateError: "Compagnon Islamique",
    hifzTitle: "Hifz",
    hifzDesc: "Suivi du Coran",
    halalTitle: "Scanner Halal",
    halalDesc: "Vérifier les ingrédients"
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [prayerData, setPrayerData] = useState<{ timings: PrayerTimes, date: HijriDate } | null>(null);
  const [loadingPrayers, setLoadingPrayers] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [language, setLanguage] = useState(() => localStorage.getItem('language') || 'en');
  const [calculationMethod, setCalculationMethod] = useState(() => parseInt(localStorage.getItem('calc_method') || '2'));
  const [darkMode, setDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    return saved === null ? window.matchMedia('(prefers-color-scheme: dark)').matches : saved === 'true';
  });

  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    localStorage.setItem('darkMode', darkMode.toString());
  }, [darkMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (p) => setLocation({ lat: p.coords.latitude, lng: p.coords.longitude }),
        () => setLocation({ lat: 51.5074, lng: -0.1278 })
      );
    }
  }, []);

  useEffect(() => {
    const fetch = async () => {
      if (!location) return;
      setLoadingPrayers(true);
      const data = await getPrayerTimes(location.lat, location.lng, calculationMethod);
      setPrayerData(data);
      setLoadingPrayers(false);
    };
    fetch();
  }, [location, calculationMethod]);

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-6 pb-24 animate-fade-in">
            <header className="flex justify-between items-center mb-6 pt-2">
              <div>
                <h1 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Noor</h1>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wider mt-1">
                  {prayerData ? `${prayerData.date.weekday.en}, ${prayerData.date.day} ${prayerData.date.month.en}` : t.dateError}
                </p>
              </div>
              <button onClick={() => setShowSettings(true)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full"><Settings size={20} /></button>
            </header>

            <PrayerCard timings={prayerData?.timings || null} loading={loadingPrayers} language={language} />

            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setActiveTab('hifz')} className="bg-emerald-50 dark:bg-emerald-950/40 p-5 rounded-3xl border border-emerald-100 dark:border-emerald-900/30 flex flex-col gap-3 text-left">
                <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white flex items-center justify-center"><Award size={20} /></div>
                <div>
                  <span className="block font-bold text-slate-800 dark:text-slate-100">{t.hifzTitle}</span>
                  <span className="text-xs text-slate-500">{t.hifzDesc}</span>
                </div>
              </button>
              <button onClick={() => setShowScanner(true)} className="bg-orange-50 dark:bg-orange-950/40 p-5 rounded-3xl border border-orange-100 dark:border-orange-900/30 flex flex-col gap-3 text-left">
                <div className="w-10 h-10 rounded-xl bg-orange-500 text-white flex items-center justify-center"><Scan size={20} /></div>
                <div>
                  <span className="block font-bold text-slate-800 dark:text-slate-100">{t.halalTitle}</span>
                  <span className="text-xs text-slate-500">{t.halalDesc}</span>
                </div>
              </button>
            </div>

            <DailyVerseCard language={language} />

            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setActiveTab('tasbih')} className="bg-blue-50 dark:bg-blue-950/40 p-5 rounded-3xl border border-blue-100 dark:border-blue-900/30 flex flex-col gap-3 text-left">
                <div className="w-10 h-10 rounded-xl bg-blue-500 text-white flex items-center justify-center"><Hand size={20} /></div>
                <span className="block font-bold">{t.tasbihTitle}</span>
              </button>
              <button onClick={() => setActiveTab('qibla')} className="bg-purple-50 dark:bg-purple-950/40 p-5 rounded-3xl border border-purple-100 dark:border-purple-900/30 flex flex-col gap-3 text-left">
                <div className="w-10 h-10 rounded-xl bg-purple-500 text-white flex items-center justify-center"><Compass size={20} /></div>
                <span className="block font-bold">{t.qiblaTitle}</span>
              </button>
            </div>
          </div>
        );
      case 'hifz': return <HifzTracker language={language} />;
      case 'quran': return <QuranReader language={language} />;
      case 'mosques': return <MosqueFinder location={location} language={language} />;
      case 'chat': return <ChatInterface language={language} />;
      case 'tasbih': return <TasbihCounter onBack={() => setActiveTab('home')} language={language} />;
      case 'qibla': return <QiblaFinder location={location} onBack={() => setActiveTab('home')} language={language} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 font-sans">
      <div className="max-w-md mx-auto min-h-screen bg-white dark:bg-slate-950 relative overflow-hidden">
        <main className="p-6 min-h-screen pb-24">
          {renderContent()}
        </main>
        <Navigation activeTab={activeTab} setActiveTab={setActiveTab} language={language} />
        <SettingsModal 
          isOpen={showSettings} onClose={() => setShowSettings(false)}
          darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)}
          language={language} setLanguage={setLanguage}
          calculationMethod={calculationMethod} setCalculationMethod={setCalculationMethod}
          prayerOffsets={{}} setPrayerOffset={() => {}} notifications={true} toggleNotifications={() => {}}
        />
        {showScanner && <HalalScanner language={language} onClose={() => setShowScanner(false)} />}
      </div>
