export const findPlaces = async (lat: number, lng: number, type: 'mosque' | 'halal', language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "", places: [] };
  const query = type === 'mosque' ? "mosques" : "halal restaurants";
  try {
    // googleMaps tool requires gemini-2.5-flash or gemini-2.5-flash-lite series
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Find the best rated ${query} nearby.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapPlaces = chunks.filter((c: any) => c.maps).map((c: any) => ({
      title: c.maps.title,
      uri: c.maps.uri,
      snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet,
      type: type
    }));
    return { text: response.text || "", places: mapPlaces };
  } catch (error) { return { text: "", places: [] }; }
};

