export const findMosques = async (lat: number, lng: number, language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "", places: [] };
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Find the best rated mosques nearby.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapPlaces = chunks.filter((c: any) => c.maps).map((c: any) => ({
      title: c.maps.title,
      uri: c.maps.uri,
      snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet,
      type: 'mosque'
    }));
    return { text: response.text || "", places: mapPlaces };
  } catch (error) { return { text: "", places: [] }; }
};

export const chatWithAi = async (message: string, history: any[], language: string = 'en'): Promise<string> => {
  if (!apiKey) return "API Key missing.";
  const langInstruction = language === 'fr' ? 'Reply in French.' : 'Reply in English.';
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are Noor, a knowledgeable Islamic AI. Help with Duas, history, and spiritual advice. Be concise and warm. ${langInstruction}`
      }
    });
    const result = await chat.sendMessage({ message });
    return result.text || "No response from AI.";
  } catch (error) { return "Error connecting to AI."; }
};

export const checkHalalIngredients = async (base64Image: string, language: string = 'en'): Promise<HalalCheckResult | null> => {
  if (!apiKey) return null;
  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
            { text: `Analyze the ingredient list in this image and determine if the product is Halal, Haram, or Doubtful according to Islamic dietary laws. Provide the result in ${langPrompt}.` }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING, enum: ['halal', 'haram', 'doubtful'] },
            reason: { type: Type.STRING },
            concerns: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["status", "reason", "concerns"],
        },
      },
    });
    return JSON.parse(response.text || '{}') as HalalCheckResult;
  } catch (error) {
    console.error("Halal scan error:", error);
    return null;
  }
};

