export const generateDailyVerse = async (language: string = 'en'): Promise<DailyVerse | null> => {
  if (!apiKey) return null;
  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a beautiful Quranic verse for today. Include Arabic text, ${langPrompt} translation, reference, and reflection.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            arabic: { type: Type.STRING },
            translation: { type: Type.STRING },
            reference: { type: Type.STRING },
            reflection: { type: Type.STRING },
          },
          required: ["arabic", "translation", "reference", "reflection"],
        },
      },
    });
    const data = JSON.parse(response.text || '{}');
    if (!data.arabic || !data.translation) return null;
    return data as DailyVerse;
  } catch (error) { 
    console.error("Daily Verse Error:", error);
    return null; 
  }
};

