import { generateDailyHadith } from '../services/geminiService';
import { DailyHadith } from '../types';
import { Share2, BookOpen, Loader2 } from 'lucide-react';

interface DailyHadithCardProps {
  language?: string;
}

const DailyHadithCard: React.FC<DailyHadithCardProps> = ({ language = 'en' }) => {
  const [hadith, setHadith] = useState<DailyHadith | null>(null);
  const [loading, setLoading] = useState(true);

  const title = language === 'fr' ? 'Hadith du Jour' : 'Daily Hadith';
  const narratorPrefix = language === 'fr' ? 'Rapporté par' : 'Narrated by';

  useEffect(() => {
    // Versioned cache key to force refresh for new category field
    const cacheKey = `dailyHadith_v2_${language}`;
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      setHadith(JSON.parse(cached));
      setLoading(false);
      return;
    }

    const fetchHadith = async () => {
      setLoading(true);
      const data = await generateDailyHadith(language);
      if (data) {
        setHadith(data);
        sessionStorage.setItem(cacheKey, JSON.stringify(data));
      }
      setLoading(false);
    };

    fetchHadith();
  }, [language]);

  if (loading) return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 flex justify-center items-center h-48 transition-colors duration-300">
        <Loader2 className="w-6 h-6 text-emerald-500 animate-spin" />
    </div>
  );

  if (!hadith) return null;

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-lg shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-800 relative group transition-colors duration-300 overflow-hidden">
        {/* Decorative Background */}
        <div className="absolute -bottom-10 -left-10 w-40 h-40 opacity-5 pointer-events-none rotate-12">
           <svg viewBox="0 0 100 100" className="w-full h-full text-slate-800 dark:text-slate-100 fill-current">
              <circle cx="50" cy="50" r="40" stroke="currentColor" strokeWidth="2" fill="none" />
              <rect x="35" y="35" width="30" height="30" transform="rotate(45 50 50)" fill="currentColor" />
           </svg>
        </div>

        <div className="relative z-10">
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-600 dark:text-slate-400">
                        <BookOpen size={16} className="fill-current" />
                    </div>
                    <h3 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">
                        {title}
                    </h3>
                </div>
                {hadith.category && (
                    <span className="px-2.5 py-1 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 text-[10px] font-bold uppercase tracking-wider border border-emerald-100 dark:border-emerald-900/30">
                        {hadith.category}
                    </span>
                )}
            </div>

            <p className="font-arabic text-xl text-slate-800 dark:text-slate-100 text-right leading-[2.2] mb-5" dir="rtl">
                {hadith.arabic}
            </p>

            <p className="text-slate-600 dark:text-slate-300 text-sm leading-relaxed mb-4">
                {hadith.translation}
            </p>

            <div className="flex justify-between items-end mt-4 pt-4 border-t border-slate-50 dark:border-slate-800/60">
                <div>
                    <p className="text-sm font-bold text-slate-800 dark:text-slate-200">{hadith.source}</p>
                    <p className="text-xs text-slate-500 dark:text-slate-500 mt-0.5">{narratorPrefix} {hadith.narrator}</p>
                </div>

                <button 
                  onClick={() => navigator.clipboard.writeText(`${hadith.translation} - ${hadith.source}`)}
                  className="w-8 h-8 flex items-center justify-center text-slate-400 dark:text-slate-500 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-full transition-colors"
                >
                    <Share2 size={16} />
                </button>
            </div>
        </div>
    </div>
  );
};

export default DailyHadithCard;

import React, { useState, useEffect, useRef } from 'react';
import { Book, ChevronRight, ArrowLeft, Search, Loader2, ScrollText, Bookmark, AlertCircle, Copy, Check, Globe } from 'lucide-react';

type Language = 'en' | 'fr';

interface BookDef {
  id: string;
  name: string;
  arabicName: string;
  author: string;
  slugs: {
    [key in Language]: string;
  } & { ar: string };
}

interface Section {
  number: string;
  title: string;
}

interface Hadith {
  hadithnumber: number;
  arabicnumber: number;
  text: string;
  grades?: { grade: string; name: string }[];
  reference?: { book: number; hadith: number };
}

interface SavedHadith {
  id: string; // composite key: bookId-hadithNumber
  bookId: string;
  bookName: string;
  en: Hadith; // This stores the translation (EN or FR) depending on what was saved
  ar?: Hadith;
  timestamp: number;
  lang?: Language; // Track which language was saved
}

interface HadithCatalogProps {
  language?: string;
}

