const HadithCatalog: React.FC<HadithCatalogProps> = ({ language = 'en' }) => {
  const [view, setView] = useState<'books' | 'sections' | 'hadiths' | 'saved'>('books');
  const [selectedBook, setSelectedBook] = useState<BookDef | null>(null);
  const [selectedSection, setSelectedSection] = useState<Section | null>(null);

  // Language State - Sync with prop
  const [contentLang, setContentLang] = useState<Language>(() => {
    return language === 'fr' ? 'fr' : 'en';
  });

  // Data States
  const [sections, setSections] = useState<Section[]>([]);
  const [hadiths, setHadiths] = useState<{ en: Hadith, ar?: Hadith }[]>([]);
  const [bookmarks, setBookmarks] = useState<SavedHadith[]>([]);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[contentLang];

  // Sync Content Language with Prop
  useEffect(() => {
    if (language === 'fr') setContentLang('fr');
    else setContentLang('en');
  }, [language]);

  // Initialize Bookmarks
  useEffect(() => {
    const saved = localStorage.getItem('noor_saved_hadiths');
    if (saved) {
      try {
        setBookmarks(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse bookmarks");
      }
    }
  }, []);

  // Persist Bookmarks
  useEffect(() => {
    localStorage.setItem('noor_saved_hadiths', JSON.stringify(bookmarks));
  }, [bookmarks]);

  // Scroll to top on view change
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = 0;
  }, [view, selectedBook, selectedSection]);

  // Refetch when language changes
  useEffect(() => {
    if (loading) return; // Prevent double fetch loops

    if (view === 'sections' && selectedBook) {
      fetchSections(selectedBook);
    } else if (view === 'hadiths' && selectedBook && selectedSection) {
      fetchHadiths(selectedBook, selectedSection.number);
    }
  }, [contentLang]);

  const fetchSections = async (book: BookDef) => {
      setLoading(true);
      setError(null);
      try {
          let slug = book.slugs[contentLang];
          let res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections.json`);

          // Fallback mechanism: If selected language fails (e.g. 404), try English
          // Note: BOOKS list now defaults FR to English slugs to avoid this, but keeping as safety.
          if (!res.ok && contentLang !== 'en') {
             console.warn(`Sections for ${slug} not found, falling back to English.`);
             slug = book.slugs['en'];
             res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections.json`);
          }

          if (!res.ok) throw new Error(t.errorSections);

          const data = await res.json();
          if (!data || Object.keys(data).length === 0) {
             throw new Error(t.noChapters);
          }

          const sectionList: Section[] = Object.entries(data)
              .map(([key, val]) => ({ number: key, title: val as string }))
              .filter(s => s.title && s.number !== '0' && s.number !== '')
              .sort((a, b) => {
                  const numA = parseFloat(a.number);
                  const numB = parseFloat(b.number);
                  return isNaN(numA) || isNaN(numB) ? a.number.localeCompare(b.number) : numA - numB;
              });

          setSections(sectionList);
          setView('sections');
      } catch (e: any) {
          console.error(e);
          setError(e.message || t.errorSections);
      } finally {
          setLoading(false);
      }
  };

  const fetchHadiths = async (book: BookDef, sectionNumber: string) => {
      setLoading(true);
      setError(null);
      try {
          // Determine slug with fallback check
          let slug = book.slugs[contentLang];

          // Fetch Translation (with fallback)
          let resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections/${sectionNumber}.json`);

          // Fallback if primary language fails
          if (!resEn.ok && contentLang !== 'en') {
              console.warn(`Hadiths for ${slug} not found, falling back to English.`);
              slug = book.slugs['en'];
              resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections/${sectionNumber}.json`);
          }

          // Fetch Arabic separately
          const resAr = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${book.slugs.ar}/sections/${sectionNumber}.json`);

          if (!resEn.ok) throw new Error(t.errorHadiths);

          let enData: { hadiths: Hadith[] } = { hadiths: [] };
          let arData: { hadiths: Hadith[] } = { hadiths: [] };

          enData = await resEn.json();
          if (resAr.ok) {
              try {
                  arData = await resAr.json();
              } catch (e) {
                  console.warn("Failed to parse Arabic JSON", e);
              }
          }

          const merged = enData.hadiths.map(hEn => {
              const hAr = arData.hadiths?.find(h => h.hadithnumber === hEn.hadithnumber);
              return { en: hEn, ar: hAr };
          });

          setHadiths(merged);
          setView('hadiths');
      } catch (e: any) {
          console.error(e);
          setError(e.message || t.errorHadiths);
      } finally {
          setLoading(false);
      }
  };

  const toggleBookmark = (item: { en: Hadith, ar?: Hadith }, book?: BookDef) => {
      const bookId = book?.id || selectedBook?.id || 'unknown';
      const bookName = book?.name || selectedBook?.name || 'Unknown Book';
      const id = `${bookId}-${item.en.hadithnumber}`;

      setBookmarks(prev => {
          const exists = prev.find(b => b.id === id);
          if (exists) {
              return prev.filter(b => b.id !== id);
          } else {
              const newBookmark: SavedHadith = {
                  id,
                  bookId,
                  bookName,
                  en: item.en,
                  ar: item.ar,
                  timestamp: Date.now(),
                  lang: contentLang
              };
              return [newBookmark, ...prev];
          }
      });
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleBookSelect = (book: BookDef) => {
      setSelectedBook(book);
      setSearchTerm('');
      fetchSections(book);
  };

  const handleSectionSelect = (section: Section) => {
      if (!selectedBook) return;
      setSelectedSection(section);
      setSearchTerm('');
      fetchHadiths(selectedBook, section.number);
  };

  const handleBack = () => {
      if (view === 'hadiths') {
          setView('sections');
          setHadiths([]);
          setSelectedSection(null);
          setSearchTerm('');
          setError(null);
      } else if (view === 'sections') {
          setView('books');
          setSections([]);
          setSelectedBook(null);
          setSearchTerm('');
          setError(null);
      } else if (view === 'saved') {
          setView('books');
          setSearchTerm('');
          setError(null);
      }
  };

  const filteredSections = sections.filter(s => s.title.toLowerCase().includes(searchTerm.toLowerCase()));
  const filteredHadiths = hadiths.filter(h => h.en.text.toLowerCase().includes(searchTerm.toLowerCase()));
  const filteredBookmarks = bookmarks.filter(b => 
      b.en.text.toLowerCase().includes(searchTerm.toLowerCase()) || 
      b.bookName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // -- RENDERERS --

  const renderBooks = () => (
      <div className="grid grid-cols-1 gap-4 px-6 pb-24">
          <div className="bg-emerald-50 dark:bg-emerald-900/20 p-6 rounded-3xl mb-4 border border-emerald-100 dark:border-emerald-900/50 text-center">
              <ScrollText size={32} className="mx-auto text-emerald-600 dark:text-emerald-400 mb-2" />
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.collections}</h2>
              <p className="text-sm text-slate-500 dark:text-slate-400">{t.subtitle}</p>
          </div>

          {BOOKS.map(book => (
              <button
                  key={book.id}
                  onClick={() => handleBookSelect(book)}
                  className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 transition-all text-left flex items-center justify-between group"
              >
                  <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400 dark:text-slate-500 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/30 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 transition-colors">
                          <Book size={20} />
                      </div>
                      <div>
                          <h3 className="font-bold text-slate-800 dark:text-slate-100">{book.name}</h3>
                          <p className="text-xs text-slate-500 dark:text-slate-400">{book.author}</p>
                      </div>
                  </div>
                  <div className="text-right">
                       <span className="block font-arabic text-lg text-emerald-600 dark:text-emerald-400">{book.arabicName}</span>
                  </div>
              </button>
          ))}
      </div>
  );

  const renderSections = () => (
      <div className="px-6 pb-24">
          <div className="sticky top-0 bg-slate-50 dark:bg-slate-950 pt-2 pb-4 z-10">
             <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder={`${t.searchChapters} ${selectedBook?.name}...`}
                   className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
          </div>

          {error ? (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                  <AlertCircle className="text-red-500 mb-2" size={32} />
                  <p className="text-slate-600 dark:text-slate-400">{error}</p>
                  <button onClick={() => selectedBook && fetchSections(selectedBook)} className="mt-4 text-emerald-600 font-medium">{t.retry}</button>
              </div>
          ) : (
              <div className="space-y-3">
                  {filteredSections.map(section => (
                      <button
                          key={section.number}
                          onClick={() => handleSectionSelect(section)}
                          className="w-full bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 transition-all text-left flex items-center gap-4 group"
                      >
                          <span className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-500 dark:text-slate-400 group-hover:text-emerald-600 dark:group-hover:text-emerald-400">
                              {section.number}
                          </span>
                          <div className="flex-1">
                              <h3 className="font-medium text-slate-800 dark:text-slate-100">{section.title}</h3>
                          </div>
                          <ChevronRight size={18} className="text-slate-300 dark:text-slate-600 group-hover:text-emerald-500" />
                      </button>
                  ))}
                  {filteredSections.length === 0 && (
                      <div className="text-center py-10 text-slate-400">{t.noChapters}</div>
                  )}
              </div>
          )}
      </div>
  );

  const renderHadithCard = (item: { en: Hadith, ar?: Hadith }, isSavedView: boolean = false) => {
    const bookId = isSavedView ? (item as any).bookId : selectedBook?.id;
    const bookName = isSavedView ? (item as any).bookName : selectedBook?.name;
    const uniqueId = `${bookId}-${item.en.hadithnumber}`;
    const saved = bookmarks.some(b => b.id === uniqueId);

    // Prepare copy text
    const copyText = `${item.en.text}\n\n${item.ar?.text || ''}\n\n${t.reference}: ${bookName}, ${t.hadith} ${item.en.hadithnumber}`;

    return (
      <div key={item.en.hadithnumber} className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 mb-4 transition-all hover:shadow-md group">
         {/* Header */}
         <div className="flex justify-between items-start mb-4 border-b border-slate-50 dark:border-slate-800 pb-4">
             <div>
                 <span className="inline-block px-2 py-1 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 text-xs font-bold rounded-lg mb-1">
                     {t.hadith} {item.en.hadithnumber}
                 </span>
                 {isSavedView && <p className="text-xs text-slate-400 mt-1">{bookName}</p>}
                 {/* For saved items, show language badge if different from current */}
                 {isSavedView && (item as any).lang && (item as any).lang !== contentLang && (
                     <span className="ml-2 text-[10px] px-1.5 py-0.5 rounded bg-slate-100 dark:bg-slate-800 text-slate-500 uppercase">
                        {(item as any).lang}
                     </span>
                 )}
             </div>

             <div className="flex gap-1">
                 <button 
                    onClick={() => handleCopy(copyText, uniqueId)}
                    className="p-2 rounded-full text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors"
                    title={t.copy}
                 >
                     {copiedId === uniqueId ? <Check size={18} className="text-emerald-500" /> : <Copy size={18} />}
                 </button>
                 <button 
                    onClick={() => toggleBookmark(item, isSavedView ? { id: bookId, name: bookName } as BookDef : undefined)}
                    className={`p-2 rounded-full transition-colors ${saved ? 'text-emerald-600 bg-emerald-50 dark:bg-emerald-900/20' : 'text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}
                    title={saved ? t.removeBookmark : t.saveBookmark}
                 >
                     {saved ? <Bookmark size={18} fill="currentColor" /> : <Bookmark size={18} />}
                 </button>
             </div>
         </div>

         {/* Arabic */}
         {item.ar && (
             <p className="font-arabic text-2xl text-right text-slate-800 dark:text-slate-100 leading-[2.2] mb-6" dir="rtl">
                 {item.ar.text}
             </p>
         )}

         {/* Translation (English or French) */}
         <p className="text-slate-600 dark:text-slate-300 leading-relaxed mb-4 text-sm">
             {item.en.text}
         </p>

         {/* Footer / Grades */}
         <div className="mt-6 pt-4 border-t border-slate-100 dark:border-slate-800">
             {/* Reference Info */}
             {item.en.reference && (
                <div className="flex items-center gap-2 mb-3 text-xs text-slate-500 dark:text-slate-400">
                    <span className="font-bold">{t.reference}:</span>
                    <span>Book {item.en.reference.book}, Hadith {item.en.reference.hadith}</span>
                </div>
             )}

             {/* Grades */}
             {item.en.grades && item.en.grades.length > 0 && (
                 <div className="space-y-2">
                     <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">{t.grades}</span>
                     <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                        {item.en.grades.map((g, i) => {
                            const gradeLower = g.grade.toLowerCase();
                            let colorClass = 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400';

                            if (gradeLower.includes('sahih')) colorClass = 'bg-emerald-50 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-800';
                            else if (gradeLower.includes('hasan')) colorClass = 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 border border-blue-100 dark:border-blue-800';
                            else if (gradeLower.includes('daif') || gradeLower.includes('weak')) colorClass = 'bg-amber-50 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border border-amber-100 dark:border-amber-800';
                            else if (gradeLower.includes('maudu') || gradeLower.includes('fabricated')) colorClass = 'bg-red-50 text-red-700 dark:bg-red-900/30 dark:text-red-400 border border-red-100 dark:border-red-800';

                            return (
                                <div key={i} className={`flex items-center justify-between px-3 py-2 rounded-lg text-xs ${colorClass}`}>
                                    <span className="font-medium capitalize">{g.grade}</span>
                                    {g.name && <span className="opacity-75 text-[10px] uppercase tracking-wide truncate max-w-[50%] text-right" title={g.name}>{g.name}</span>}
                                </div>
                            );
                        })}
                     </div>
                 </div>
             )}
         </div>
      </div>
    );
  };

  const renderHadithList = () => (
      <div className="px-6 pb-24">
          <div className="sticky top-0 bg-slate-50 dark:bg-slate-950 pt-2 pb-4 z-10">
             <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder={t.searchHadith}
                   className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
          </div>

          {error ? (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                  <AlertCircle className="text-red-500 mb-2" size={32} />
                  <p className="text-slate-600 dark:text-slate-400">{error}</p>
                  <button onClick={() => selectedBook && selectedSection && fetchHadiths(selectedBook, selectedSection.number)} className="mt-4 text-emerald-600 font-medium">{t.retry}</button>
              </div>
          ) : (
             <div>
                 {filteredHadiths.length > 0 ? (
                     filteredHadiths.map(h => renderHadithCard(h))
                 ) : (
                     <div className="text-center py-10 text-slate-400">{t.noHadiths}</div>
                 )}
             </div>
          )}
      </div>
  );

  const renderSaved = () => (
      <div className="px-6 pb-24">
          <div className="sticky top-0 bg-slate-50 dark:bg-slate-900 pt-2 pb-4 z-10 mb-4">
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100 mb-2">{t.savedTitle}</h2>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder={t.searchSaved}
                   className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
          </div>

          {bookmarks.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center text-slate-400">
                  <Bookmark size={48} className="mb-4 opacity-20" />
                  <p>{t.noSaved}</p>
              </div>
          ) : (
              <div>
                  {filteredBookmarks.map(b => renderHadithCard(b as any, true))}
              </div>
          )}
      </div>
  );

  return (
    <div className="h-full flex flex-col animate-fade-in relative bg-slate-50 dark:bg-slate-950 transition-colors duration-300" ref={scrollRef}>
       {/* Header */}
       <div className="px-6 py-4 flex items-center justify-between sticky top-0 bg-slate-50/95 dark:bg-slate-950/95 backdrop-blur-sm z-20">
           {view === 'books' ? (
               <div className="flex items-center justify-between w-full">
                   <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">Hadith</h1>

                   <div className="flex items-center gap-2">
                       <a 
                          href="https://www.hadith.com/"
                          target="_blank"
                          rel="noopener noreferrer"
                          className="p-2 bg-white dark:bg-slate-900 rounded-full shadow-sm text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors"
                          title={t.visitWebsite}
                       >
                           <Globe size={20} />
                       </a>
                       <button 
                          onClick={() => setView('saved')}
                          className="p-2 bg-white dark:bg-slate-900 rounded-full shadow-sm text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-emerald-400"
                       >
                           <Bookmark size={20} />
                       </button>
                   </div>
               </div>
           ) : (
               <div className="flex items-center justify-between w-full">
                   <div className="flex items-center gap-4 flex-1">
                       <button onClick={handleBack} className="p-2 -ml-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-300 transition-colors">
                           <ArrowLeft size={22} />
                       </button>
                       <div>
                           <h2 className="font-bold text-slate-800 dark:text-slate-100 line-clamp-1">
                               {view === 'saved' ? t.saved : view === 'sections' ? selectedBook?.name : selectedSection?.title}
                           </h2>
                           {view !== 'saved' && (
                               <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-1">
                                   {view === 'sections' ? t.selectChapter : selectedBook?.name}
                               </p>
                           )}
                       </div>
                   </div>
               </div>
           )}
       </div>

       {/* Content */}
       <div className="flex-1 overflow-y-auto">
           {loading ? (
               <div className="flex justify-center pt-20">
                   <Loader2 className="animate-spin text-emerald-600" size={32} />
               </div>
           ) : (
               <>
                   {view === 'books' && renderBooks()}
                   {view === 'sections' && renderSections()}
                   {view === 'hadiths' && renderHadithList()}
                   {view === 'saved' && renderSaved()}
               </>
           )}
       </div>
    </div>
  );
};

export default HadithCatalog;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import PrayerCard from './components/PrayerCard';
import ChatInterface from './components/ChatInterface';
import MosqueFinder from './components/MosqueFinder';
import DailyVerseCard from './components/DailyVerseCard';
import DailyHadithCard from './components/DailyHadithCard';
import QiblaFinder from './components/QiblaFinder';
import TasbihCounter from './components/TasbihCounter';
import QuranReader from './components/QuranReader';
import ProphetStories from './components/ProphetStories';
import SettingsModal from './components/SettingsModal';
import { getPrayerTimes } from './services/prayerService';
import { PrayerTimes, HijriDate } from './types';
import { Settings, Compass, Hand, Quote, BookOpen, ScrollText } from 'lucide-react';

const TRANSLATIONS = {
  en: {
    tasbihTitle: "Tasbih",
    qiblaTitle: "Qibla",
    mosquesTitle: "Mosques",
    chatTitle: "Ask Noor AI",
    storiesTitle: "Stories",
    dateError: "Islamic Companion",
    dailyInspo: "Daily Inspiration",
    dailyHadith: "Prophetic Wisdom"
  },
  fr: {
    tasbihTitle: "Tasbih",
    qiblaTitle: "Qibla",
    mosquesTitle: "Mosquées",
    chatTitle: "Demander à l'IA",
    storiesTitle: "Histoires",
    dateError: "Compagnon Islamique",
    dailyInspo: "Inspiration du Jour",
    dailyHadith: "Sagesse Prophétique"
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [prayerData, setPrayerData] = useState<{ timings: PrayerTimes, date: HijriDate } | null>(null);
  const [loadingPrayers, setLoadingPrayers] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  const [language, setLanguage] = useState(() => localStorage.getItem('language') || 'en');
  const [calculationMethod, setCalculationMethod] = useState(() => parseInt(localStorage.getItem('calc_method') || '2'));
  const [darkMode, setDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    return saved === null ? window.matchMedia('(prefers-color-scheme: dark)').matches : saved === 'true';
  });

  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    localStorage.setItem('darkMode', darkMode.toString());
  }, [darkMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (p) => setLocation({ lat: p.coords.latitude, lng: p.coords.longitude }),
        () => setLocation({ lat: 51.5074, lng: -0.1278 })
      );
    }
  }, []);

  useEffect(() => {
    const fetch = async () => {
      if (!location) return;
      setLoadingPrayers(true);
      const data = await getPrayerTimes(location.lat, location.lng, calculationMethod);
      setPrayerData(data);
      setLoadingPrayers(false);
    };
    fetch();
  }, [location, calculationMethod]);

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-6 pb-24 animate-fade-in">
            <header className="flex justify-between items-center mb-6 pt-2">
              <div>
                <h1 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Noor</h1>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wider mt-1">
                  {prayerData ? `${prayerData.date.weekday.en}, ${prayerData.date.day} ${prayerData.date.month.en}` : t.dateError}
                </p>
              </div>
              <button onClick={() => setShowSettings(true)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full transition-transform active:scale-90"><Settings size={20} /></button>
            </header>

            <PrayerCard timings={prayerData?.timings || null} loading={loadingPrayers} language={language} />

            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setActiveTab('tasbih')} className="bg-blue-50 dark:bg-blue-950/40 p-4 rounded-3xl border border-blue-100 dark:border-blue-900/30 flex flex-col items-center gap-2 text-center transition-all hover:shadow-md active:scale-95">
                <div className="w-10 h-10 rounded-xl bg-blue-500 text-white flex items-center justify-center shadow-lg shadow-blue-500/20"><Hand size={20} /></div>
                <span className="text-[10px] font-bold text-slate-800 dark:text-slate-100 uppercase tracking-widest">{t.tasbihTitle}</span>
              </button>
              <button onClick={() => setActiveTab('qibla')} className="bg-purple-50 dark:bg-purple-950/40 p-4 rounded-3xl border border-purple-100 dark:border-purple-900/30 flex flex-col items-center gap-2 text-center transition-all hover:shadow-md active:scale-95">
                <div className="w-10 h-10 rounded-xl bg-purple-500 text-white flex items-center justify-center shadow-lg shadow-purple-500/20"><Compass size={20} /></div>
                <span className="text-[10px] font-bold text-slate-800 dark:text-slate-100 uppercase tracking-widest">{t.qiblaTitle}</span>
              </button>
              <button onClick={() => setActiveTab('stories')} className="col-span-2 bg-amber-50 dark:bg-amber-950/40 p-4 rounded-3xl border border-amber-100 dark:border-amber-900/30 flex flex-col items-center gap-2 text-center transition-all hover:shadow-md active:scale-95">
                <div className="w-10 h-10 rounded-xl bg-amber-500 text-white flex items-center justify-center shadow-lg shadow-amber-500/20"><ScrollText size={20} /></div>
                <span className="text-[10px] font-bold text-slate-800 dark:text-slate-100 uppercase tracking-widest">{t.storiesTitle}</span>
              </button>
            </div>

            <div className="grid gap-6">
              <section>
                <div className="flex items-center gap-2 mb-3 px-1">
                  <BookOpen size={16} className="text-emerald-500" />
                  <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.dailyInspo}</h2>
                </div>
                <DailyVerseCard language={language} />
              </section>

              <section>
                <div className="flex items-center gap-2 mb-3 px-1">
                  <Quote size={16} className="text-blue-500" />
                  <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.dailyHadith}</h2>
                </div>
                <DailyHadithCard language={language} />
              </section>
            </div>
          </div>
        );
      case 'quran': return <QuranReader language={language} />;
      case 'mosques': return <MosqueFinder location={location} language={language} />;
      case 'chat': return <ChatInterface language={language} />;
      case 'tasbih': return <TasbihCounter onBack={() => setActiveTab('home')} language={language} />;
      case 'qibla': return <QiblaFinder location={location} onBack={() => setActiveTab('home')} language={language} />;
      case 'stories': return <ProphetStories onBack={() => setActiveTab('home')} language={language} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 font-sans">
      <div className="max-w-md mx-auto min-h-screen bg-white dark:bg-slate-950 relative overflow-hidden shadow-2xl">
        <main className="p-6 min-h-screen pb-24">
          {renderContent()}
        </main>
        <Navigation activeTab={activeTab} setActiveTab={setActiveTab} language={language} />
        <SettingsModal 
          isOpen={showSettings} onClose={() => setShowSettings(false)}
          darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)}
          language={language} setLanguage={setLanguage}
          calculationMethod={calculationMethod} setCalculationMethod={setCalculationMethod}
          prayerOffsets={{}} setPrayerOffset={() => {}} notifications={true} toggleNotifications={() => {}}
        />
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Home, MapPin, MessageCircle, BookOpen, ScrollText } from 'lucide-react';

interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  language?: string;
}

const TRANSLATIONS = {
  en: { home: 'Home', quran: 'Quran', mosques: 'Mosques', chat: 'Ask AI', stories: 'Stories' },
  fr: { home: 'Accueil', quran: 'Coran', mosques: 'Mosquées', chat: 'IA', stories: 'Histoires' }
};

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab, language = 'en' }) => {
  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  const navItems = [
    { id: 'home', icon: Home, label: t.home },
    { id: 'quran', icon: BookOpen, label: t.quran },
    { id: 'stories', icon: ScrollText, label: t.stories },
    { id: 'mosques', icon: MapPin, label: t.mosques },
    { id: 'chat', icon: MessageCircle, label: t.chat },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-lg border-t border-slate-200 dark:border-slate-800 pb-4 pt-2 px-2 shadow-[0_-4px_10px_rgba(0,0,0,0.03)] z-50 md:hidden transition-all duration-300">
      <div className="flex justify-between items-center max-w-sm mx-auto">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`relative flex flex-col items-center gap-1 p-2 rounded-2xl transition-all duration-300 w-12 sm:w-14 group ${
                isActive 
                  ? 'text-emerald-600 dark:text-emerald-400' 
                  : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'
              }`}
            >
              {/* Active Indicator Background */}
              {isActive && (
                <div className="absolute inset-0 bg-emerald-50 dark:bg-emerald-900/20 rounded-2xl -z-10 animate-fade-in scale-100 opacity-100"></div>
              )}

              <div className={`relative p-1 transition-transform duration-300 ${isActive ? '-translate-y-0.5' : ''}`}>
                 <Icon size={24} strokeWidth={isActive ? 2.5 : 2} className="transition-all" />
              </div>

              <span className={`text-[10px] font-medium transition-all duration-300 ${isActive ? 'font-bold scale-105' : 'font-medium'} truncate w-full text-center`}>
                {item.label}
              </span>

              {/* Bottom Dot for Active State */}
              {isActive && (
                 <span className="absolute bottom-1 w-1 h-1 bg-current rounded-full"></span>
              )}
            </button>
          );
        })}
      </div>
    </nav>
  );
};

