  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[contentLang as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  // Initial Load & Language Sync
  useEffect(() => {
    setContentLang(language === 'fr' ? 'fr' : 'en');
  }, [language]);

  // Load Bookmarks
  useEffect(() => {
    const saved = localStorage.getItem('noor_saved_hadiths_v2');
    if (saved) {
      try {
        setBookmarks(JSON.parse(saved));
      } catch (e) { console.error(e); }
    }
  }, []);

  // Save Bookmarks
  useEffect(() => {
    localStorage.setItem('noor_saved_hadiths_v2', JSON.stringify(bookmarks));
  }, [bookmarks]);

  // Scroll Reset
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = 0;
  }, [view, selectedBook, selectedSection]);

  const fetchSections = async (book: BookDef) => {
    setLoading(true);
    setError(null);
    try {
      // Check cache
      const cacheKey = `sections_${book.id}_${contentLang}`;
      const cached = sessionStorage.getItem(cacheKey);
      if (cached) {
        setSections(JSON.parse(cached));
        setView('sections');
        setLoading(false);
        return;
      }

      let slug = book.slugs[contentLang];
      let res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections.json`);

      // Fallback to English if current lang fails (common for French in this API)
      if (!res.ok && contentLang !== 'en') {
        slug = book.slugs['en'];
        res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections.json`);
      }

      if (!res.ok) throw new Error(t.errorSections);

      const data = await res.json();
      if (!data) throw new Error(t.noChapters);

      const sectionList: Section[] = Object.entries(data)
        .map(([key, val]) => ({ number: key, title: val as string }))
        .filter(s => s.title && s.number !== '0' && s.number !== '')
        .sort((a, b) => parseFloat(a.number) - parseFloat(b.number));

      setSections(sectionList);
      sessionStorage.setItem(cacheKey, JSON.stringify(sectionList));
      setView('sections');
    } catch (e) {
      setError(t.errorSections);
    } finally {
      setLoading(false);
    }
  };

  const fetchHadiths = async (book: BookDef, sectionNumber: string) => {
    setLoading(true);
    setError(null);
    try {
      const cacheKey = `hadiths_${book.id}_${sectionNumber}_${contentLang}`;
      const cached = sessionStorage.getItem(cacheKey);
      if (cached) {
        setHadiths(JSON.parse(cached));
        setView('hadiths');
        setLoading(false);
        return;
      }

      let slug = book.slugs[contentLang];
      let resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections/${sectionNumber}.json`);

      if (!resEn.ok && contentLang !== 'en') {
        slug = book.slugs['en'];
        resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slug}/sections/${sectionNumber}.json`);
      }

      // Fetch Arabic
      const resAr = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${book.slugs.ar}/sections/${sectionNumber}.json`);

      if (!resEn.ok) throw new Error(t.errorHadiths);

      const enData = await resEn.json();
      let arData = { hadiths: [] };
      if (resAr.ok) arData = await resAr.json();

      const merged = enData.hadiths.map((hEn: Hadith) => {
        const hAr = arData.hadiths?.find((h: Hadith) => h.hadithnumber === hEn.hadithnumber);
        return { en: hEn, ar: hAr };
      });

      setHadiths(merged);
      sessionStorage.setItem(cacheKey, JSON.stringify(merged));
      setView('hadiths');
    } catch (e) {
      setError(t.errorHadiths);
    } finally {
      setLoading(false);
    }
