              <Bookmark size={18} fill={saved ? "currentColor" : "none"} />
            </button>
          </div>
        </div>

        {item.ar && (
          <p className="font-arabic text-2xl text-right text-slate-800 dark:text-slate-100 leading-[2.2] mb-5" dir="rtl">
            {item.ar.text}
