            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder={view === 'sections' ? t.searchChapters : t.searchHadith}
              className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-2.5 pl-9 pr-4 text-sm text-slate-800 dark:text-slate-100 placeholder:text-slate-400 outline-none focus:ring-2 focus:ring-emerald-500/20"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        )}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">
        {loading ? (
          <div className="flex justify-center pt-20"><Loader2 className="animate-spin text-emerald-600" size={32} /></div>
        ) : error ? (
          <div className="text-center py-20 text-slate-500">
            <AlertCircle className="mx-auto mb-2 text-red-400" size={32} />
            <p>{error}</p>
            <button onClick={() => selectedBook && fetchSections(selectedBook)} className="mt-4 text-emerald-600 font-bold text-sm">{t.retry}</button>
          </div>
        ) : (
          <>
            {/* BOOKS VIEW */}
            {view === 'books' && (
              <div className="grid gap-4">
                <div className="bg-emerald-50 dark:bg-emerald-900/20 p-5 rounded-2xl flex items-center gap-4 border border-emerald-100 dark:border-emerald-900/50">
                   <div className="w-12 h-12 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center text-emerald-600 shadow-sm">
                      <Database size={24} />
                   </div>
                   <div>
                      <h3 className="font-bold text-emerald-900 dark:text-emerald-100">{t.onlineMode}</h3>
                      <p className="text-xs text-emerald-700 dark:text-emerald-300">{t.onlineDesc}</p>
                   </div>
                </div>

                {BOOKS.map(book => (
                  <button
                    key={book.id}
                    onClick={() => handleBookSelect(book)}
                    className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm flex justify-between items-center group hover:border-emerald-200 dark:hover:border-emerald-800 transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 group-hover:text-emerald-600 transition-colors">
                        <Book size={20} />
                      </div>
                      <div className="text-left">
                        <h3 className="font-bold text-slate-800 dark:text-slate-100">{book.name}</h3>
                        <p className="text-xs text-slate-500">{book.author}</p>
                      </div>
                    </div>
                    <span className="font-arabic text-emerald-600/50 dark:text-emerald-400/30 text-lg">{book.arabicName}</span>
                  </button>
                ))}
              </div>
            )}

            {/* SECTIONS VIEW */}
            {view === 'sections' && (
              <div className="space-y-2">
                {filteredSections.length > 0 ? (
                  filteredSections.map(section => (
                    <button
                      key={section.number}
                      onClick={() => handleSectionSelect(section)}
                      className="w-full bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 flex items-center gap-4 hover:border-emerald-300 dark:hover:border-emerald-700 transition-all text-left group"
                    >
                      <span className="text-xs font-bold text-slate-400 w-6">{section.number}</span>
                      <span className="flex-1 font-medium text-slate-800 dark:text-slate-100 group-hover:text-emerald-700 dark:group-hover:text-emerald-400">{section.title}</span>
                      <ChevronRight size={16} className="text-slate-300 group-hover:text-emerald-500" />
                    </button>
                  ))
                ) : (
                  <p className="text-center text-slate-400 py-10">{t.noChapters}</p>
                )}
              </div>
            )}

            {/* HADITHS VIEW */}
            {view === 'hadiths' && (
              <div>
                {filteredHadiths.length > 0 ? filteredHadiths.map(h => renderHadithCard(h)) : <p className="text-center text-slate-400 py-10">{t.noHadiths}</p>}
              </div>
            )}

            {/* SAVED VIEW */}
            {view === 'saved' && (
              <div>
                {filteredBookmarks.length > 0 ? filteredBookmarks.map(b => renderHadithCard(b as any, true)) : (
                  <div className="text-center py-20 text-slate-400 flex flex-col items-center">
                    <Bookmark size={48} className="mb-4 opacity-20" />
                    <p>{t.noSaved}</p>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default HadithCollection;

